// Adjacency list node
struct AdjNode {
    int vertex;
    struct AdjNode *next;
};
struct AdjNode* adjList[MAX_VERTICES];

void bfs(int start, int V) {
    int visited[MAX_VERTICES] = {0};
    int queue[MAX_VERTICES], front = 0, rear = 0;
    visited[start] = 1;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        printf("%d ", u);
        struct AdjNode *temp = adjList[u];
        while (temp != NULL) {
            if (!visited[temp->vertex]) {
                visited[temp->vertex] = 1;
                queue[rear++] = temp->vertex;
            }
            temp = temp->next;
        }
    }
}

int visited[MAX_VERTICES] = {0};

void dfs(int u) {
    visited[u] = 1;
    printf("%d ", u);
    struct AdjNode *temp = adjList[u];
    while (temp != NULL) {
        if (!visited[temp->vertex]) dfs(temp->vertex);
        temp = temp->next;
    }
}
